#include <stdio.h>
#include <math.h>

/*
 * CPU Performance Measurement Calculator
 * Demonstrates: CPU Time = (IC × CPI) / Clock Rate
 * and performance analysis concepts
 */

// Structure to hold CPU parameters
typedef struct {
 double instruction_count;
 double cpi; // Cycles Per Instruction
 double clock_rate_hz; // Clock rate in Hz
 char name[32];
} CPU;

// Structure for performance results
typedef struct {
 double cpu_time; // Execution time in seconds
 double clock_cycles; // Total clock cycles
 double throughput; // Instructions per second
} PerformanceResult;


/*
 * Calculate CPU performance metrics
 * CPU Time = (Instruction Count × CPI) / Clock Rate
 */
PerformanceResult calculate_performance(CPU cpu) {
 PerformanceResult result;

 // Total clock cycles = IC × CPI
 result.clock_cycles = cpu.instruction_count * cpu.cpi;

 // CPU Time = Clock Cycles / Clock Rate
 result.cpu_time = result.clock_cycles / cpu.clock_rate_hz;

 // Throughput = Instructions per second
 result.throughput = cpu.instruction_count / result.cpu_time;

 return result;
}


/*
 * Calculate speedup using Amdahl's Law
 * Speedup = 1 / [(1 - F) + (F / S)]
 * where F = fraction enhanced, S = speedup of enhanced part
 */
double calculate_amdahl_speedup(double fraction_enhanced, double speedup_enhanced) {
 double unenhanced = 1.0 - fraction_enhanced;
 double enhanced_contribution = fraction_enhanced / speedup_enhanced;

 return 1.0 / (unenhanced + enhanced_contribution);
}


/*
 * Compare two CPUs and print detailed comparison
 */
void compare_cpus(CPU a, CPU b) {
 PerformanceResult perf_a = calculate_performance(a);
 PerformanceResult perf_b = calculate_performance(b);

 double time_ratio = perf_b.cpu_time / perf_a.cpu_time;

 printf("\n========================================\n");
 printf(" CPU Performance Comparison\n");
 printf("========================================\n\n");

 printf("%-20s %15s %15s\n", "Metric", a.name, b.name);
 printf("%-20s %15s %15s\n", "------", "-----", "-----");
 printf("%-20s %15.2f GHz %15.2f GHz\n", "Clock Rate", 
 a.clock_rate_hz/1e9, b.clock_rate_hz/1e9);
 printf("%-20s %15.2f %15.2f\n", "CPI", a.cpi, b.cpi);
 printf("%-20s %15.2e %15.2e\n", "Instruction Count", 
 a.instruction_count, b.instruction_count);
 printf("%-20s %15.2e %15.2e\n", "Clock Cycles", 
 perf_a.clock_cycles, perf_b.clock_cycles);
 printf("%-20s %12.4f sec %12.4f sec\n", "Execution Time", 
 perf_a.cpu_time, perf_b.cpu_time);
 printf("%-20s %15.2e %15.2e\n", "Throughput (IPC)", 
 perf_a.throughput, perf_b.throughput);

 printf("\n----------------------------------------\n");
 if (time_ratio > 1.0) {
 printf("Result: %s is %.2fx FASTER\n", a.name, time_ratio);
 } else {
 printf("Result: %s is %.2fx FASTER\n", b.name, 1.0/time_ratio);
 }
 printf("----------------------------------------\n");
}


/*
 * Analyze Amdahl's Law for various enhancement scenarios
 */
void analyze_amdahl(double original_time) {
 double fractions[] = {0.2, 0.4, 0.6, 0.8, 0.95};
 double speedups[] = {2, 5, 10, 20};
 int f_count = sizeof(fractions) / sizeof(fractions[0]);
 int s_count = sizeof(speedups) / sizeof(speedups[0]);

 printf("\n========================================\n");
 printf(" Amdahl's Law Speedup Analysis\n");
 printf("========================================\n\n");

 for (int i = 0; i < f_count; i++) {
 printf("Enhanced Fraction: %.0f%%\n", fractions[i] * 100);
 printf("%-15s %-15s %-15s\n", "Enhancement", "Speedup", "New Time");
 printf("%-15s %-15s %-15s\n", "-----------", "-------", "--------");

 for (int j = 0; j < s_count; j++) {
 double speedup = calculate_amdahl_speedup(fractions[i], speedups[j]);
 double new_time = original_time / speedup;
 printf("%-15.0fx %-15.4f %-15.4f sec\n", 
 speedups[j], speedup, new_time);
 }
 printf("\n");
 }
}


int main() {
 // Example 1: Basic CPU time calculation
 printf("========================================\n");
 printf(" CPU Performance Calculator Demo\n");
 printf("========================================\n");

 CPU cpu1;
 cpu1.instruction_count = 4e9; // 4 billion instructions
 cpu1.cpi = 1.0;
 cpu1.clock_rate_hz = 2e9; // 2 GHz
 snprintf(cpu1.name, sizeof(cpu1.name), "CPU 1");

 PerformanceResult result1 = calculate_performance(cpu1);

 printf("\nExample 1: Basic CPU Time Calculation\n");
 printf("----------------------------------------\n");
 printf("Instruction Count: %.2e\n", cpu1.instruction_count);
 printf("CPI: %.1f\n", cpu1.cpi);
 printf("Clock Rate: %.1f GHz\n", cpu1.clock_rate_hz/1e9);
 printf("Total Clock Cycles: %.2e\n", result1.clock_cycles);
 printf("CPU Execution Time: %.2f seconds\n", result1.cpu_time);
 printf("Throughput: %.2e instructions/sec\n", result1.throughput);

 // Example 2: Compare two processors (textbook example)
 CPU cpu_a, cpu_b;

 cpu_a.instruction_count = 1e9;
 cpu_a.cpi = 2.0;
 cpu_a.clock_rate_hz = 4e9; // 4 GHz
 snprintf(cpu_a.name, sizeof(cpu_a.name), "CPU A");

 cpu_b.instruction_count = 1e9;
 cpu_b.cpi = 1.5;
 cpu_b.clock_rate_hz = 3e9; // 3 GHz
 snprintf(cpu_b.name, sizeof(cpu_b.name), "CPU B");

 compare_cpus(cpu_a, cpu_b);

 // Example 3: Amdahl's Law analysis
 double original_time = result1.cpu_time;
 analyze_amdahl(original_time);

 // Example 4: Specific Amdahl example from textbook
 printf("========================================\n");
 printf(" Textbook Example: 40%% enhanced, 3x speedup\n");
 printf("========================================\n");

 double speedup = calculate_amdahl_speedup(0.40, 3.0);
 printf("\nFraction Enhanced: 40%%\n");
 printf("Enhancement Speedup: 3x\n");
 printf("Overall Speedup: %.2fx\n", speedup);
 printf("(Matches textbook result of ~1.36x)\n");

 return 0;
}
